import { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { auth } from '@/lib/firebase';
import {
  signInWithEmailAndPassword,
  signOut,
  onAuthStateChanged,
  User as FirebaseUser,
} from 'firebase/auth';

interface User {
  name: string;
  email: string;
  role: string;
}

interface AuthContextType {
  user: User | null;
  isAuthenticated: boolean;
  loading: boolean;
  login: (email: string, password: string) => Promise<boolean>;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | null>(null);

// Map Firebase users to app roles
const USER_ROLES: Record<string, { name: string; role: string }> = {
  'admin@crede.ce.gov.br': { name: 'Coordenador Regional', role: 'Administrador' },
  'gestor@crede.ce.gov.br': { name: 'Gestor Escolar', role: 'Gestor' },
  'tecnico@crede.ce.gov.br': { name: 'Técnico Regional', role: 'Técnico' },
};

function firebaseUserToAppUser(fbUser: FirebaseUser): User {
  const email = fbUser.email ?? '';
  const mapped = USER_ROLES[email] ?? { name: email, role: 'Usuário' };
  return { name: mapped.name, email, role: mapped.role };
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsub = onAuthStateChanged(auth, (fbUser) => {
      setUser(fbUser ? firebaseUserToAppUser(fbUser) : null);
      setLoading(false);
    });
    return unsub;
  }, []);

  const login = async (email: string, password: string): Promise<boolean> => {
    try {
      await signInWithEmailAndPassword(auth, email.trim().toLowerCase(), password);
      return true;
    } catch {
      return false;
    }
  };

  const logout = () => {
    signOut(auth);
    setUser(null);
  };

  if (loading) {
    return null; // ou um spinner de loading
  }

  return (
    <AuthContext.Provider value={{ user, isAuthenticated: !!user, loading, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
}
